import{_ as c}from"./D4KBtqE8.js";import{_ as g}from"./BwZa6nzS.js";import{_ as d}from"./CLrkComU.js";import{_ as m}from"./_K_4blRM.js";import{h as p}from"./Co8n4-y3.js";import{u as f}from"./Bj77Cqq1.js";import{h as s,j as i,O as n,F as z,H as _,f as a,g as b,B as t}from"./BA8T4pJX.js";import"./CrSMfh9x.js";const e={seo:{title:"Veranstaltungsschutz | Black Forest Security GmbH",description:"Professioneller Veranstaltungsschutz in Freiburg: individuelle Konzepte, Zugangskontrolle, Parkplatzservice und Notausgangsüberwachung."},title:"Veranstaltungsschutz",lead:"Ihr individuelles Sicherheitskonzept – von der Konzeption bis zur Umsetzung.",sections:[{id:"konzept",title:"Ihr individuelles Sicherheitskonzept",paragraphs:["Konzentrieren Sie sich voll und ganz auf Ihr Fachgebiet und vertrauen darauf, dass die Spezialisten von Black Forest Security Ihr persönliches und individuell angepasstes Sicherheitskonzept erstellen. Unsere umfangreiche Erfahrung im Bereich der Veranstaltungssicherheit sowie ein umfassendes Netzwerk in der gesamten Branche zeichnen uns aus.","Wir bieten professionelle Sicherheitslösungen, beginnend bei der Konzeption bis hin zur Umsetzung. Verlassen Sie sich auf unsere ganzheitlichen Dienstleistungen aus einer Hand."]},{id:"experte",title:"Der Experte für professionelle Veranstaltungen",paragraphs:["In Ihrer Rolle als Veranstalter stehen Sie vor zahlreichen Herausforderungen, die in den Zuständigkeitsbereich Ihres Sicherheitsdienstes fallen. Daher ist es entscheidend, einen robusten und zuverlässigen Partner an Ihrer Seite zu haben, dem Sie voll und ganz vertrauen können.","Mit langjähriger Erfahrung als Dienstleister für Veranstaltungen, sowohl bei großen als auch kleinen Events, sind wir bestens in den Bereichen Behörden und Branche vernetzt. Wir kümmern uns engagiert um alle Sicherheitsbelange, die Ihre Veranstaltung betreffen."]}],features:[{title:"Zugangskontrolle",description:"Unsere Mitarbeiter, speziell im Umgang mit Ihren Gästen geschult, übernehmen die Betreuung Ihres Eingangsbereichs. Bei Bedarf bieten wir auch technische Unterstützung an, immer diskret und in Übereinstimmung mit geltenden Gesetzen."},{title:"Parkplatzservice",description:"Wir kümmern uns darum, die An- und Abreise Ihrer Gäste so angenehm wie möglich zu gestalten, indem wir den Parkplatz des Veranstaltungsortes betreuen."},{title:"Notausgangsüberwachung",description:"Um stets ein Höchstmaß an Sicherheit für Sie und Ihre Gäste zu gewährleisten, legen wir während der Veranstaltung besonderen Wert auf die Überwachung der vorgeschriebenen Notausgänge."}]},N={__name:"veranstaltungsschutz",setup(k){return f({title:e.seo.title,meta:[{name:"description",content:e.seo.description}],htmlAttrs:{lang:"de"}}),(v,S)=>{const l=c,u=g,o=d,h=m;return t(),s("div",null,[i(l,{image:n(p).veranstaltungsschutz,title:n(e).title,lead:n(e).lead},null,8,["image","title","lead"]),(t(!0),s(z,null,_(n(e).sections,r=>(t(),a(u,{key:r.id,title:r.title,paragraphs:r.paragraphs},null,8,["title","paragraphs"]))),128)),n(e).features?(t(),a(o,{key:0,items:n(e).features},null,8,["items"])):b("",!0),i(h)])}}};export{N as default};
